from langgraph.types import Command
from langgraph.graph import StateGraph, START, END
from typing import Annotated
from typing_extensions import TypedDict
from langgraph.graph.message import add_messages

class P2PState(TypedDict):
    messages: Annotated[list, add_messages]
    task: str
    research_done: bool
    code_done: bool

def researcher_agent(state: P2PState) -> Command:
    # Do research work...
    findings = call_research_llm(state["task"])
    # Hand off directly to the coder agent
    return Command(
        goto="coder_agent",
        update={
            "messages": [{"role": "assistant", "content": findings, "name": "researcher"}],
            "research_done": True,
        }
    )

def coder_agent(state: P2PState) -> Command:
    code = call_coding_llm(state["messages"])
    return Command(
        goto="writer_agent",
        update={
            "messages": [{"role": "assistant", "content": code, "name": "coder"}],
            "code_done": True,
        }
    )

def writer_agent(state: P2PState) -> dict:
    # Terminal agent — returns dict (no handoff)
    final = call_writing_llm(state["messages"])
    return {"messages": [{"role": "assistant", "content": final, "name": "writer"}]}

graph = StateGraph(P2PState)
graph.add_node("researcher_agent", researcher_agent)
graph.add_node("coder_agent", coder_agent)
graph.add_node("writer_agent", writer_agent)
graph.add_edge(START, "researcher_agent")
graph.add_edge("writer_agent", END)
# No edges between researcher→coder or coder→writer — Command handles routing
app = graph.compile()

from typing import Literal

def researcher(state: MultiAgentState) -> dict:
    try:
        docs = web_search(state["task"])
        return {"research_docs": docs, "error": ""}
    except RateLimitError as e:
        # Signal failure — supervisor will reroute
        return {"error": f"researcher failed: {e}"}

class Route(BaseModel):
    next: Literal["researcher", "coder", "writer", "error_handler", "FINISH"]

def supervisor(state: MultiAgentState) -> dict:
    if state.get("error"):
        return {"next": "error_handler"}
    # ... normal routing logic ...
    response = supervisor_llm.invoke(state["messages"])
    return {"next": response.next}

def error_handler(state: MultiAgentState) -> dict:
    # Log, notify, or attempt recovery
    return {
        "messages": [{"role": "assistant", "content": f"Task failed: {state['error']}"}],
        "next": "FINISH",
        "error": "",
    }
